import './Post.css'
import React, { Component } from 'react'
import { Link } from 'react-router-dom';

export default class Post extends Component {
    render() {
        // const { img, id, title } = this.props.list
        const { tags,img, author, text, link, id, title } = this.props.list
        return (
            <Link to={`/posts/${id}`} className="card-post" onClick={() => { this.props.openWindPots(id) }}>
                {title}
                {img}
                {tags}
                {id}
                {id}
                <img className="img-post" width="100%" src={img} alt={`title: ${title}`} />
            </Link >
        )
    }
}
